1	/** A live cell on the infinite Game of Life grid, expressed as `[x, y]`. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const toKey = ([x, y]: Cell): string => `${x},${y}`;
11	const fromKey = (key: string): Cell => {
12	  const [xs, ys] = key.split(",");
13	  return [Number(xs), Number(ys)];
14	};
15	
16	const willBeAlive = (isAlive: boolean, neighborCount: number): boolean =>
17	  (isAlive && neighborCount === 2) || neighborCount === 3;
18	
19	const countNeighbors = (liveCells: Cell[]): Map<string, number> => {
20	  const counts = new Map<string, number>();
21	  for (const [x, y] of liveCells) {
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      const key = toKey([x + dx, y + dy]);
24	      counts.set(key, (counts.get(key) ?? 0) + 1);
25	    }
26	  }
27	  return counts;
28	};
29	
30	/**
31	 * Computes the next generation of live cells from the current generation,
32	 * following Conway's Game of Life rules.
33	 */
34	export function nextGeneration(liveCells: Cell[]): Cell[] {
35	  const liveSet = new Set(liveCells.map(toKey));
36	  return Array.from(countNeighbors(liveCells))
37	    .filter(([key, count]) => willBeAlive(liveSet.has(key), count))
38	    .map(([key]) => fromKey(key));
39	}
