1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each with only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a 2x2 block (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
28	    const lTromino: [number, number][] = [[0, 1], [1, 1], [0, 0]];
29	    const expected: [number, number][] = [[0, 1], [1, 1], [0, 0], [1, 0]];
30	    const result = nextGeneration(lTromino);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
35	    const input: [number, number][] = [
36	      [0, 0], [1, 0], [2, 0],
37	      [1, 1],
38	      [0, 2], [1, 2], [2, 2],
39	    ];
40	    const result = nextGeneration(input);
41	    const containsCenter = result.some(([x, y]) => x === 1 && y === 1);
42	    expect(containsCenter).toBe(false);
43	  });
44	  it.todo("should handle negative coordinates");
45	});
