type NeighborCensus = {
  counts: Map<string, number>;
  liveKeys: Set<string>;
};

const censusNeighbors = (liveCells: Cell[]): NeighborCensus => {
  const counts = new Map<string, number>();
  const liveKeys = new Set<string>();
  for (const cell of liveCells) {
    liveKeys.add(toKey(cell));
    const [x, y] = cell;
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = toKey([x + dx, y + dy]);
      counts.set(key, (counts.get(key) ?? 0) + 1);
    }
  }
  return { counts, liveKeys };
};

/**
 * Computes the next generation of live cells from the current generation,
 * following Conway's Game of Life rules.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const { counts, liveKeys } = censusNeighbors(liveCells);
  const survivors: Cell[] = [];
  for (const [key, count] of counts) {
    if (willBeAlive(liveKeys.has(key), count)) survivors.push(fromKey(key));
  }
  return survivors;
}
